from collections import deque
from typing import List

def solve(edges: List[List[int]], online: List[bool], k: int) -> int:
    n = len(online)
    adj = [[] for _ in range(n)]
    in_degree = [0] * n
    for u, v, cost in edges:
        adj[u].append((v, cost))
        in_degree[v] += 1

    # Compute topological order
    q = deque()
    for i in range(n):
        if in_degree[i] == 0:
            q.append(i)
    topo = []
    while q:
        u = q.popleft()
        topo.append(u)
        for v, cost in adj[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0:
                q.append(v)

    # Binary search for maximum minimum edge cost
    max_cost = 0
    for u, v, cost in edges:
        if cost > max_cost:
            max_cost = cost
    low, high = 0, max_cost
    answer = -1

    while low <= high:
        mid = (low + high) // 2
        dist = [float('inf')] * n
        dist[0] = 0
        for u in topo:
            if not online[u]:
                continue
            for (v, cost) in adj[u]:
                if cost >= mid and online[v]:
                    if dist[v] > dist[u] + cost:
                        dist[v] = dist[u] + cost
        if dist[n-1] <= k:
            answer = mid
            low = mid + 1
        else:
            high = mid - 1

    return answer if answer != -1 else -1
